code = """import pandas as pd\nimport re\nimport json\n\nbusinesses_data = locals()[\'var_function-call-10626385321230539986\']\n\nbusiness_categories_list = []\ncategory_patterns = [\n    r\"providing a range of services in (.*)\\\.\",\n    r\"offers a wide range of services, including (.*)\\\.\",\n    r\"offers a premier destination for (.*)\\\.\",\n    r\"establishment offers a range of services including (.*)\\\.\",\n    r\"business offers a diverse range of services and products in the fields of (.*)\\\.\"\n]\n\nfor business in businesses_data:\n    description = business.get(\'description\', \'\')\n    extracted_categories_str = None\n    for pattern in category_patterns:\n        match = re.search(pattern, description)\n        if match:\n            extracted_categories_str = match.group(1).strip()\n            break\n    \n    if extracted_categories_str:\n        # Split by comma and \" and \" to get individual categories\n        temp_categories = extracted_categories_str.replace(\' and \', \',\')\n        categories = [cat.strip() for cat in temp_categories.split(\',\') if cat.strip()]\n        for category in categories:\n            business_categories_list.append({\n                \'business_id\': business[\'business_id\'],\n                \'category\': category\n            })\n\ndf_categories = pd.DataFrame(business_categories_list)\n\nif not df_categories.empty:\n    category_counts = df_categories[\'category\'].value_counts().reset_index()\n    category_counts.columns = [\'category\', \'business_count\']\n    \n    most_common_category_info = category_counts.loc[category_counts[\'business_count\'].idxmax()]\n    most_common_category_name = most_common_category_info[\'category\']\n    \n    businesses_in_most_common_category = df_categories[\n        df_categories[\'category\'] == most_common_category_name\n    ][\'business_id\'].tolist()\nelse:\n    most_common_category_name = \"N/A\"\n    businesses_in_most_common_category = []\n\nresult = {\n    \"most_common_category\": most_common_category_name,\n    \"businesses_for_avg_rating\": businesses_in_most_common_category\n}\n\nprint(\"__RESULT__:\")\nprint(json.dumps(result))"""

